const port = env.get('port');
const baud = Number(env.get('baud'));
const timeoutMs = Number(env.get('timeout_ms')) || 2000;

if (!port) { node.error('port env var must be set', msg); return null; }
if (isNaN(baud) || baud <= 0) { node.error('invalid baud', msg); return null; }

msg._cfg = { port, baud, timeoutMs, tx: msg.payload };
msg._start = Date.now();
// Command an exec-based serial round-trip using stty + cat/echo pattern.
// This is a portable approach that doesn't require the community serialport node.
const payload = JSON.stringify(String(msg.payload));
msg.payload = `sh -c 'stty -F ${port} ${baud} raw -echo && printf %s ${payload} > ${port} & timeout ${timeoutMs / 1000} cat ${port}'`;
return msg;

const rc = msg.rc && typeof msg.rc.code === 'number' ? msg.rc.code : null;
const text = (typeof msg.payload === 'string') ? msg.payload : '';

if (rc === null) {
    msg._buf = (msg._buf || '') + text;
    return null;
}

const rx = msg._buf || '';
const elapsed = Date.now() - msg._start;

msg.payload = {
    success: rc === 0 && rx.length > 0,
    tx: msg._cfg.tx,
    rx: rx,
    elapsed_ms: elapsed,
    exit_code: rc,
    timestamp: new Date().toISOString()
};

delete msg._cfg;
delete msg._start;
delete msg._buf;
return msg;
